In order to get more information about the heap, I created a patch that dumps the heap just before the crash. This is the patch:

commit e75d21fe2d5ce7408b6280dd796f68580668b1ae (HEAD -> master)
Author: Breno Leitao <breno.leitao@gmail.com>
Date:   Wed Jan 24 13:04:58 2018 +0100

    libsa: Dump the heap

diff --git a/stand/libsa/zalloc.c b/stand/libsa/zalloc.c
index 4d1ec629121..7a5007f4b46 100644
--- a/stand/libsa/zalloc.c
+++ b/stand/libsa/zalloc.c
@@ -144,6 +144,20 @@ znalloc(MemPool *mp, uintptr_t bytes)
  * zfree() - free previously allocated memory
  */

+void dumpHeap(MemPool *mp){
+       MemNode **pmn;
+       MemNode *mn;
+
+       printf("Mempool base %p and end %p\n", mp->mp_Base, mp->mp_End);
+       printf(" mp_Size %x and mp_Used %x\n", mp->mp_Size, mp->mp_Used);
+
+       for (pmn = &mp->mp_First; (mn = *pmn) != NULL; pmn = &mn->mr_Next) {
+               printf("MN = %p and Byte is %x\n", mn, mn->mr_Bytes);
+       }
+
+}
+
 void
 zfree(MemPool *mp, void *ptr, uintptr_t bytes)
 {
@@ -220,7 +234,8 @@ zfree(MemPool *mp, void *ptr, uintptr_t bytes)
                /* NOT REACHED */
            }
            if ((char *)ptr < (char *)mn + mn->mr_Bytes) {
-               panic("zfree(%p,%ju): corrupt memlist2", ptr,
+               dumpHeap(mp);
+               printf("zfree(%p,%ju): corrupt memlist2", ptr,
                    (uintmax_t)bytes);
            }
        }

Once I boot the broken kernel, this is the info I get:

/boot/kernel/kernel data=0x11ef978+0x4c6e48 syms=[0x8+0x1684e0

Mempool base 0x1810d40 and end 0x18a7d40
 mp_Size 97000 and mp_Used 83e80
MN = 0x182d900 and Byte is 64cab8

zfree(0x183c080,4224): corrupt memlist2 
elf64_loadimage: could not read symbols - skipped! (491520 != 1475808)

Mempool base 0x1810d40 and end 0x18a7d40
 mp_Size 97000 and mp_Used 83080
MN = 0x182d900 and Byte is 64cab8
MN = 0x183c080 and Byte is 1080

----

Trying to understand the problem, there is an allocation of 0x1080 (4224 in decimal) bytes at 0x183c080 but free() and free is complaining that this is not 4224 bytes long. Not sure what might be wrong here.
